section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/slo-burn-decision-matrix.json",
  "type": "object",
  "required": [
    "matrix_version",
    "portfolio_id",
    "rows",
    "audit_destination",
    "default_cell"
  ],
  "properties": {
    "matrix_version": {
      "type": "string",
      "description": "string (semver)"
    },
    "portfolio_id": {
      "type": "string",
      "description": "string"
    },
    "rows": {
      "type": "array",
      "description": "array (each {burn_category, service_class, action, owner, revert_criteria})"
    },
    "audit_destination": {
      "type": "string",
      "description": "string (log store URL)"
    },
    "default_cell": {
      "type": "string",
      "description": "string (escalate | accept)"
    }
  }
}
